index b345b9f5..b6d3c83c 100644
--- a/src/resources/extensions/workflow/post-execution-checks.ts
+++ b/src/resources/extensions/workflow/post-execution-checks.ts
@@ -318,10 +318,14 @@ export function checkImportResolution(
     const imports = extractRelativeImports(source);

     for (const { importPath, lineNum } of imports) {
-      // React Router generated +types modules may not exist on disk during
-      // post-exec checks (generated during framework build). Don't block task
-      // completion on these imports.
-      if (/^\.{1,2}\/\+types\//.test(importPath)) {
+      // React Router generated +types modules and SvelteKit generated $types
+      // modules may not exist on disk during post-exec checks (generated during
+      // framework build). The $types pattern matches nested-route imports like
+      // `../../routes/blog/$types`. Don't block task completion on these imports.
+      if (
+        /^\.{1,2}\/\+types\//.test(importPath) ||
+        /^(?:\.{1,2}\/)+(?:[^/]+\/)*\$types(?:$|\/)/.test(importPath)
+      ) {
         continue;
       }

diff --git a/src/resources/extensions/workflow/tests/post-execution-checks.test.ts b/src/resources/extensions/workflow/tests/post-execution-checks.test.ts
index 43463a33..d892a120 100644
--- a/src/resources/extensions/workflow/tests/post-execution-checks.test.ts
+++ b/src/resources/extensions/workflow/tests/post-execution-checks.test.ts
@@ -451,6 +451,28 @@ describe("checkImportResolution", () => {
     }
   });

+  test("ignores nested generated SvelteKit $types imports", () => {
+    tempDir = join(tmpdir(), `post-exec-test-${Date.now()}`);
+    mkdirSync(tempDir, { recursive: true });
+    mkdirSync(join(tempDir, "src", "lib", "components"), { recursive: true });
+    writeFileSync(
+      join(tempDir, "src", "lib", "components", "RouteCard.ts"),
+      "import type { PageData } from '../../routes/blog/$types';\nexport const data = {} as PageData;"
+    );
+
+    try {
+      const task = createTask({
+        id: "T01",
+        key_files: ["src/lib/components/RouteCard.ts"],
+      });
+
+      const results = checkImportResolution(task, [], tempDir);
+      assert.deepEqual(results, []);
+    } finally {
+      rmSync(tempDir, { recursive: true, force: true });
+    }
+  });
+
   test("fails when import doesn't resolve", () => {
     tempDir = join(tmpdir(), `post-exec-test-${Date.now()}`);
     mkdirSync(tempDir, { recursive: true });

